export const getCostEstimateResponseInputAnnualExpensesAntifoulingEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesRefitReserveEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesEngineServiceEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesGeneratorServiceEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesElectronicsServiceEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesSafetyEquipmentEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesTenderServiceEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesHullPaintEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesRiggingServiceEurMin = 0;

export const getCostEstimateResponseInputAnnualExpensesWatermakerServiceEurMin = 0;

export const getCostEstimateResponseInputBrokerCommissionPctMin = 0;
export const getCostEstimateResponseInputBrokerCommissionPctMax = 100;

export const getCostEstimateResponseInputFinancingLoanAmountEurMin = 0;

export const getCostEstimateResponseInputFinancingInterestRatePctMin = 0;
export const getCostEstimateResponseInputFinancingInterestRatePctMax = 30;

export const getCostEstimateResponseInputFinancingTermYearsMax = 40;

export const GetCostEstimateResponse = zod.object({
  id: zod.string(),
  created_at: zod.string(),
  name: zod.string().nullish(),
  input: zod.object({
    yacht_name: zod.string().nullish(),
    builder: zod
      .string()
      .nullish()
      .describe("Shipyard \/ builder (e.g. Sunseeker, Ferretti)"),
    model: zod
      .string()
      .nullish()
      .describe("Yacht model (e.g. Predator 74, Navetta 33)"),
    yacht_class: zod.enum([
      "motor_yacht",
      "sailing_yacht",
      "catamaran",
      "superyacht",
    ]),
    length_meters: zod
      .number()
      .min(getCostEstimateResponseInputLengthMetersMin)
      .max(getCostEstimateResponseInputLengthMetersMax),
    year_built: zod
      .number()
      .min(getCostEstimateResponseInputYearBuiltMin)
      .max(getCostEstimateResponseInputYearBuiltMax),
    region: zod.enum([
      "mediterranean",
      "northern_europe",
      "caribbean",
      "asia_pacific",
      "middle_east",
      "global",
    ]),
    usage_type: zod.enum(["private", "mixed", "charter_focused"]),
    crew: zod.array(
      zod.object({
        position: zod
          .string()
          .describe(
            "Position key (captain, first_officer, chief_engineer, chef, stewardess, deckhand, bosun, security)",
          ),
        enabled: zod.boolean(),
        monthly_salary_eur: zod
          .number()
          .min(getCostEstimateResponseInputCrewItemMonthlySalaryEurMin)
          .nullish(),
        quantity: zod
          .number()
          .min(1)
          .max(getCostEstimateResponseInputCrewItemQuantityMax)
          .nullish()
          .describe("Only meaningful for stewardess\/deckhand"),
        months_per_year: zod
          .number()
          .min(1)
          .max(getCostEstimateResponseInputCrewItemMonthsPerYearMax)
          .nullish()
          .describe(
            "Months of employment per year. Only honored for stewardess\/deckhand (seasonal). All other positions are treated as 12.",
          ),
      }),
    ),
    monthly_expenses: zod.object({
      mooring_eur: zod
        .number()
        .min(getCostEstimateResponseInputMonthlyExpensesMooringEurMin)
        .nullish(),
      fuel_eur: zod
        .number()
        .min(getCostEstimateResponseInputMonthlyExpensesFuelEurMin)
        .nullish(),
      provisioning_eur: zod
        .number()
        .min(getCostEstimateResponseInputMonthlyExpensesProvisioningEurMin)
        .nullish(),
      communications_eur: zod
        .number()
        .min(getCostEstimateResponseInputMonthlyExpensesCommunicationsEurMin)
        .nullish(),
      maintenance_eur: zod
        .number()
        .min(getCostEstimateResponseInputMonthlyExpensesMaintenanceEurMin)
        .nullish(),
    }),
    annual_expenses: zod.object({
      insurance_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesInsuranceEurMin)
        .nullish(),
      registration_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesRegistrationEurMin)
        .nullish(),
      classification_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesClassificationEurMin)
        .nullish(),
      antifouling_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesAntifoulingEurMin)
        .nullish(),
      refit_reserve_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesRefitReserveEurMin)
        .nullish(),
      engine_service_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesEngineServiceEurMin)
        .nullish()
        .describe(
          "Main engine(s) annual service — oil, filters, impellers, injectors",
        ),
      generator_service_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesGeneratorServiceEurMin)
        .nullish()
        .describe("Generator(s) annual service"),
      electronics_service_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesElectronicsServiceEurMin)
        .nullish()
        .describe("Navigation \/ electronics calibration & service"),
      safety_equipment_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesSafetyEquipmentEurMin)
        .nullish()
        .describe(
          "Life raft, EPIRB, fire suppression, flares — annual certification",
        ),
      tender_service_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesTenderServiceEurMin)
        .nullish()
        .describe("Tender \/ outboard annual service"),
      hull_paint_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesHullPaintEurMin)
        .nullish()
        .describe("Topside polish \/ paint touch-ups (annualized)"),
      rigging_service_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesRiggingServiceEurMin)
        .nullish()
        .describe(
          "Standing \/ running rigging inspection (sailing & catamaran)",
        ),
      watermaker_service_eur: zod
        .number()
        .min(getCostEstimateResponseInputAnnualExpensesWatermakerServiceEurMin)
        .nullish()
        .describe("Watermaker membrane replacement & service"),
    }),
    broker_commission_pct: zod
      .number()
      .min(getCostEstimateResponseInputBrokerCommissionPctMin)
      .max(getCostEstimateResponseInputBrokerCommissionPctMax)
      .nullish(),
    financing: zod.object({
      type: zod.enum(["cash", "loan"]),
      loan_amount_eur: zod
        .number()
        .min(getCostEstimateResponseInputFinancingLoanAmountEurMin)
        .nullish(),
      interest_rate_pct: zod
        .number()
        .min(getCostEstimateResponseInputFinancingInterestRatePctMin)
        .max(getCostEstimateResponseInputFinancingInterestRatePctMax)
        .nullish(),
      term_years: zod
        .number()
        .min(1)
        .max(getCostEstimateResponseInputFinancingTermYearsMax)
        .nullish(),
    }),
  }),
  result: zod.object({
    total_annual_eur: zod.number(),
    cost_per_day_eur: zod.number(),
    cost_per_week_eur: zod.number(),
    crew_total_eur: zod.number(),
    operations_total_eur: zod.number(),
    maintenance_total_eur: zod.number(),
    financing_total_eur: zod.number(),
    crew_breakdown: zod.array(
      zod.object({
        category: zod.string(),
        amount_eur: zod.number(),
        formula: zod.string().nullish(),
      }),
    ),
    operations_breakdown: zod.array(
      zod.object({
        category: zod.string(),
        amount_eur: zod.number(),
        formula: zod.string().nullish(),
      }),
    ),
    maintenance_breakdown: zod.array(
      zod.object({
        category: zod.string(),
        amount_eur: zod.number(),
        formula: zod.string().nullish(),
      }),
    ),
    financing_breakdown: zod.array(
      zod.object({
        category: zod.string(),
        amount_eur: zod.number(),
        formula: zod.string().nullish(),
      }),
    ),
    category_summary: zod.array(
      zod.object({
        category: zod.string(),
        amount_eur: zod.number(),
        color_hint: zod.string(),
      }),
    ),
    charter_break_even_weeks: zod.number().nullish(),
    currency: zod.string(),
    legal_disclaimer: zod.string(),
    yacht_name: zod.string().nullish(),
    builder: zod.string().nullish(),
    model: zod.string().nullish(),
    yacht_class: zod.enum([
      "motor_yacht",
      "sailing_yacht",
      "catamaran",
      "superyacht",
    ]),
    length_meters: zod.number(),
    year_built: zod.number(),
  }),
});

/**
 * @summary Delete a saved annual cost estimate
 */
export const DeleteCostEstimateParams = zod.object({
  id: zod.coerce.string(),
});

/**
 * @summary Get a saved ROI calculation by id
 */
export const GetRoiCalculationParams = zod.object({
  id: zod.coerce.string(),
});

export const getRoiCalculationResponseInputManualRateEurMin = 0;

export const getRoiCalculationResponseInputManualCharterUnitsMin = 0;
export const getRoiCalculationResponseInputManualCharterUnitsMax = 366;

export const getRoiCalculationResponseInputManagementFeePctMin = 0;
export const getRoiCalculationResponseInputManagementFeePctMax = 50;

export const getRoiCalculationResponseInputTargetWeeksMin = 0;
export const getRoiCalculationResponseInputTargetWeeksMax = 52;

export const getRoiCalculationResponseResultRiskScoreMax = 10;

export const getRoiCalculationResponseResultRevenueByMonthItemMonthMax = 12;

export const GetRoiCalculationResponse = zod.object({
  id: zod.string(),
  yacht_id: zod.string(),
  created_at: zod.string(),
  input: zod.object({
    yacht_id: zod.string(),
    region: zod.enum([
      "mediterranean",
      "caribbean",
      "northern_europe",
      "asia_pacific_me",
      "middle_east",
    ]),
    season: zod
      .union([zod.enum(["high", "shoulder", "low", "mixed"]), zod.null()])
      .optional()
      .describe("Default 'mixed' (weighted across high\/shoulder\/low)"),
    management_style: zod.enum([
      "owner_operated",
      "management_company",
      "brokerage",
    ]),
    occupancy_target: zod
      .union([
        zod.enum(["conservative", "realistic", "optimistic"]),
        zod.null(),
      ])
      .optional()
      .describe("Hint for AI mode; ignored in manual modes"),
    pricing_mode: zod
      .enum(["manual_daily", "manual_weekly", "ai"])
      .describe(
        "How the charter rate is determined:\n\* manual_daily  — user provides daily rate + number of charter days\n\* manual_weekly — user provides weekly rate + number of charter weeks\n\* ai            — engine asks AI (web-search) for plausible rate + weeks\n",
      ),
    manual_rate_eur: zod
      .number()
      .min(getRoiCalculationResponseInputManualRateEurMin)
      .nullish()
      .describe(
        "Per-day rate for manual_daily, per-week rate for manual_weekly",
      ),
    manual_charter_units: zod
      .number()
      .min(getRoiCalculationResponseInputManualCharterUnitsMin)
      .max(getRoiCalculationResponseInputManualCharterUnitsMax)
      .nullish()
      .describe(
        "Number of charter days OR weeks per year, matching pricing_mode",
      ),
    management_fee_pct: zod
      .number()
      .min(getRoiCalculationResponseInputManagementFeePctMin)
      .max(getRoiCalculationResponseInputManagementFeePctMax)
      .nullish()
      .describe("Override default management fee; null = uses style default"),
    target_weeks: zod
      .number()
      .min(getRoiCalculationResponseInputTargetWeeksMin)
      .max(getRoiCalculationResponseInputTargetWeeksMax)
      .nullish()
      .describe("AI mode only — override AI-predicted charter weeks"),
  }),
  result: zod.object({
    id: zod.string().nullish(),
    annual_revenue_eur: zod.number(),
    annual_expenses_eur: zod.number(),
    net_profit_eur: zod.number(),
    roi_pct: zod.number(),
    payback_years: zod.number(),
    occupancy_pct: zod.number(),
    expected_charter_weeks: zod.number(),
    avg_daily_rate_eur: zod.number(),
    daily_rate_low_season_eur: zod.number().nullish(),
    daily_rate_high_season_eur: zod.number().nullish(),
    market_rating: zod
      .union([
        zod.literal("A"),
        zod.literal("B"),
        zod.literal("C"),
        zod.literal("D"),
        zod.literal(null),
      ])
      .nullish(),
    risk_score: zod
      .number()
      .min(1)
      .max(getRoiCalculationResponseResultRiskScoreMax)
      .nullish(),
    currency: zod.string(),
    expenses: zod.array(
      zod.object({
        category: zod.string(),
        amount_eur: zod.number(),
        formula: zod.string().nullish(),
      }),
    ),
    revenue_by_month: zod.array(
      zod.object({
        month: zod
          .number()
          .min(1)
          .max(getRoiCalculationResponseResultRevenueByMonthItemMonthMax),
        value_eur: zod.number(),
      }),
    ),
    depreciation_curve: zod.array(
      zod.object({
        year_offset: zod.number(),
        value_eur: zod.number(),
      }),
    ),
    roi_projection_5y: zod.array(
      zod.object({
        year_offset: zod.number(),
        value_eur: zod.number(),
      }),
    ),
    comparables: zod
      .array(
        zod.object({
          name: zod.string(),
          location: zod.string().nullish(),
          weekly_rate_eur: zod.number().nullish(),
          source_url: zod.string().nullish(),
        }),
      )
      .optional(),
    reasoning: zod.string(),
    recommendations: zod.array(zod.string()).optional(),
    confidence: zod.enum(["high", "medium", "low"]),
    legal_disclaimer: zod.string(),
  }),
});

/**
 * @summary Delete a saved ROI calculation
 */
export const DeleteRoiCalculationParams = zod.object({
  id: zod.coerce.string(),
});
